const text = $json.content.parts[0].text;

return [
  {
    json: JSON.parse(text)
  }
];

const input = $input.first().json;

let standardized = {};
let index = 1;

// loop through all form fields
for (const key in input) {

  // skip unwanted fields
  if (key === "submittedAt" || key === "formMode") continue;

  // assign as Question1, Question2...
  standardized[`Question${index}`] = input[key];
  index++;
}

// keep submittedAt if exists
if (input.submittedAt) {
  standardized.submittedAt = input.submittedAt;
}

return [
  {
    json: standardized
  }
];

