const raw = $json.content?.parts?.[0]?.text || "";

// Safer extraction
const toMatch = raw.match(/To:\s*(.*)/i);
const subjectMatch = raw.match(/Subject:\s*(.*)/i);

// Email content extraction (multiline)
let message = "";
if (raw.includes("Email Content:")) {
  message = raw.split(/Email Content:/i)[1].trim();
}

// Clean values
const to = toMatch ? toMatch[1].split("\n")[0].trim() : "";
const subject = subjectMatch ? subjectMatch[1].split("\n")[0].trim() : "";

// Return
return [
  {
    json: {
      to,
      subject,
      message
    }
  }
];

// Step 1: Get raw text
let raw = $json.content?.parts?.[0]?.text || "";

// Step 2: Fix escaped newlines
raw = raw.replace(/\\n/g, "\n");

// Step 3: Validate
if (!raw || typeof raw !== "string") {
  return [{ json: { screening_questions: "No valid data" } }];
}

// Step 4: Extract questions section
let questionsBlock = raw;

if (raw.toLowerCase().includes("screening questions")) {
  const splitData = raw.split(/screening questions:?/i);
  questionsBlock = splitData.length > 1 ? splitData[1] : raw;
}

// Step 5: Split properly using numbering
const questions = questionsBlock
  .split(/\d+\.\s+/)
  .map(q => q.trim())
  .filter(q => q.length > 0);

// Step 6: Clean EACH question (REMOVE SPECIAL CHARS 🔥)
let cleanedQuestions = questions.map(q => {
  return q
    .replace(/["']/g, "")        // remove quotes
    .replace(/\\/g, "")          // remove slashes
    .replace(/\s+/g, " ")        // normalize spaces
    .trim();
});

// Step 7: Build final clean text
let finalText = "";

cleanedQuestions.forEach((q, index) => {
  finalText += `${index + 1}. ${q}\n\n`;
});

// Step 8: Return
return [
  {
    json: {
      screening_questions: finalText.trim()
    }
  }
];
